class Solution:
    def maxSubarrayLength(self, nums, k):
        n = len(nums)
        best = 0
        for i in range(n):
            counts = {}
            for j in range(i, n):
                counts[nums[j]] = counts.get(nums[j], 0) + 1
                if counts[nums[j]] > k:
                    break
                best = max(best, j - i + 1)
        return best

